    public User {
        if (score < 0) throw new IllegalArgumentException();
    }
}

sealed interface Expr permits Lit, Add { }
final class Lit implements Expr { int v() { return 0; } }
final class Add implements Expr { }

static int eval(Expr e) {
    return switch (e) {
        case Lit l -> 0;
        case Add a -> 1;
    };
}
